import React from "react";
import { Box, Grid, HStack, VStack, Text, SimpleGrid } from "@chakra-ui/react";
import { osmosTheme } from "./index";

// Extract tokens from the theme
const tokens = osmosTheme.theme.tokens || {};
const semanticTokens = osmosTheme.theme.semanticTokens || {};

// Individual token categories
const colors = tokens.colors || {};
const fonts = tokens.fonts || {};
const fontSizes = tokens.fontSizes || {};
const fontWeights = tokens.fontWeights || {};
const spacing = tokens.spacing || {};
const radii = tokens.radii || {};
const shadows = tokens.shadows || {};
const animations = tokens.animations || {};
const aspectRatios = tokens.aspectRatios || {};
const blurs = tokens.blurs || {};
const borders = tokens.borders || {};
const cursor = tokens.cursor || {};
const durations = tokens.durations || {};
const easings = tokens.easings || {};
const letterSpacings = tokens.letterSpacings || {};
const lineHeights = tokens.lineHeights || {};
const sizes = tokens.sizes || {};
const zIndex = tokens.zIndex || {};

// Semantic tokens
const semanticColors = semanticTokens.colors || {};
const semanticShadows = semanticTokens.shadows || {};
const semanticRadii = semanticTokens.radii || {};

export default {
  title: "Theme/Design Tokens",
  tags: ["autodocs"],
};

// ============================================================================
// HELPER COMPONENTS
// ============================================================================

const ColorSwatch = ({ name, shades }) => (
  <VStack align="stretch" gap="0">
    <Text fontWeight="bold" fontSize="sm" mb="2" textTransform="capitalize">
      {name}
    </Text>
    {Object.entries(shades).map(([shade, colorValue]) => {
      const value = colorValue.value || colorValue;
      const isDark = parseInt(shade) >= 500;
      return (
        <HStack key={shade} bg={value} p="3" justify="space-between">
          <Text fontSize="xs" color={isDark ? "white" : "black"} fontWeight="medium">
            {shade}
          </Text>
          <Text fontSize="xs" color={isDark ? "white" : "black"} fontFamily="mono">
            {value}
          </Text>
        </HStack>
      );
    })}
  </VStack>
);

const TokenDisplay = ({ name, value, showValue = true }) => (
  <Box p="3" borderWidth="1px" borderRadius="md">
    <Text fontSize="sm" fontWeight="medium" mb="1">
      {name}
    </Text>
    {showValue && (
      <Text fontSize="xs" color="gray.500" fontFamily="mono">
        {value}
      </Text>
    )}
  </Box>
);

