// ============================================================================
// SEMANTIC TOKENS STORIES
// ============================================================================

const SemanticTokenDisplay = ({ name, tokenData }) => {
  const hasLightDark =
    tokenData.value &&
    typeof tokenData.value === "object" &&
    (tokenData.value._light || tokenData.value._dark);

  return (
    <Box p="4" borderWidth="1px" borderRadius="md">
      <Text fontSize="sm" fontWeight="medium" mb="2">
        {name}
      </Text>
      {hasLightDark ? (
        <VStack align="stretch" gap="2">
          <HStack>
            <Text fontSize="xs" color="gray.500" minW="12">
              Light:
            </Text>
            <Text fontSize="xs" fontFamily="mono" color="gray.600">
              {tokenData.value._light}
            </Text>
          </HStack>
          <HStack>
            <Text fontSize="xs" color="gray.500" minW="12">
              Dark:
            </Text>
            <Text fontSize="xs" fontFamily="mono" color="gray.600">
              {tokenData.value._dark}
            </Text>
          </HStack>
        </VStack>
      ) : (
        <Text fontSize="xs" color="gray.500" fontFamily="mono">
          {tokenData.value || JSON.stringify(tokenData)}
        </Text>
      )}
    </Box>
  );
};

